const data = $('Notion - Student_Study 재조회').item.json.properties;
const student = $('Notion - Students 조회').item.json;
const notionPageId = $('Webhook').item.json.body.data.id;

let prevClassStudy = null;
try {
  prevClassStudy = $('Notion - 지난수업 조회').item.json;
} catch(e) {
  prevClassStudy = null;
}

const 학생이름 = student.properties?.['이름']?.title?.[0]?.plain_text || student.name || '';
const 학부모연락처1 = student.properties?.['보호자전화번호(모)']?.phone_number || '';
const 학부모연락처2 = student.properties?.['보호자전화번호(부)']?.phone_number || '';

const 수업일시Raw = data['수업일시']?.date?.start || '';
let 수업날짜 = '';
let 요일 = '';
if (수업일시Raw) {
  const d = new Date(수업일시Raw);
  const dayNames = ['일', '월', '화', '수', '목', '금', '토'];
  요일 = dayNames[d.getDay()];
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const min = String(d.getMinutes()).padStart(2, '0');
  수업날짜 = `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

const 수업회차 = (data['수업회차']?.multi_select || []).map(s => s.name).join(', ');
const 과정 = (data['과정']?.rollup?.array || []).flatMap(item => (item.multi_select || []).map(s => s.name)).join(', ');

const 다음수업일Raw = data['다음수업일']?.rollup?.array?.[0]?.date?.start || '';
let 다음수업일 = '';
if (다음수업일Raw) {
  const d2 = new Date(다음수업일Raw);
  const dayNames2 = ['일', '월', '화', '수', '목', '금', '토'];
  const yyyy = d2.getFullYear();
  const mm = String(d2.getMonth() + 1).padStart(2, '0');
  const dd = String(d2.getDate()).padStart(2, '0');
  const dow = dayNames2[d2.getDay()];
  다음수업일 = `${yyyy}-${mm}-${dd}(${dow})`;
}

const 기타안내 = data['기타안내']?.rich_text?.[0]?.plain_text || '';
const 수업구분 = data['수업구분']?.rollup?.array?.[0]?.select?.name || '';
const 수업내용 = data['진도/수업 내용']?.rollup?.array?.[0]?.rich_text?.[0]?.plain_text || '';
const 지난과제 = prevClassStudy?.properties?.['과제']?.rich_text?.[0]?.plain_text || '';

const reportParams = { url_day: notionPageId, 학생이름, 수업날짜, 요일, 수업회차, 과정, 수업내용, 지난과제 };
const reportRecipientList = [];
if (학부모연락처1) reportRecipientList.push({ recipientNo: 학부모연락처1, templateParameter: reportParams });
if (학부모연락처2) reportRecipientList.push({ recipientNo: 학부모연락처2, templateParameter: reportParams });

function extractNumber(val) {
  const match = String(val || '').match(/\d+/);
  return match ? parseInt(match[0], 10) : null;
}
const numFromSession = extractNumber(수업회차);
const numFromCourse = extractNumber(수업구분);
const sendPaymentNotice = (numFromSession !== null && numFromCourse !== null && numFromSession === numFromCourse);

const paymentParams = { 이름: 학생이름, 수업구분, 수업일시: 수업날짜, 요일, 다음수업일, 기타안내 };
const paymentRecipientList = [];
if (학부모연락처1) paymentRecipientList.push({ recipientNo: 학부모연락처1, templateParameter: paymentParams });
if (학부모연락처2) paymentRecipientList.push({ recipientNo: 학부모연락처2, templateParameter: paymentParams });

return [{ json: { reportData: { senderKey: '7780249050d98477b04a1b589e4794c8ac1f7a78', templateCode: 'Math4U-edu-2025002', recipientList: reportRecipientList }, paymentData: { senderKey: '7780249050d98477b04a1b589e4794c8ac1f7a78', templateCode: 'Math4U-edu-2025004', recipientList: paymentRecipientList }, sendPaymentNotice, notionPageId } }];

